function getUrlVars(t){let n={};return t.replace(/[?&]+([^=&]+)=([^&]*)/gi,function(t,e,r){n[e]=r}),n}function getRandom(t,n){return Math.floor(Math.random()*(n-t+1))+t}function getRandomString(t){const n="ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789";let e="";for(let r=0;r<parseInt(t);r++)e+=n[getRandom(0,n.length-1)];return e}